SELECT COUNT(*) AS total_likes
FROM content_likes
WHERE content_id = 123;

SELECT content_id, user_id, like_date
FROM content_likes
ORDER BY like_date DESC;

SELECT content_id, COUNT(like_id) AS like_count
FROM content_likes
GROUP BY content_id;

SELECT content_id, AVG(rating_value) AS average_rating
FROM content_ratings
GROUP BY content_id;
